1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string };
16	
17	function isBlockOfThreeSameType(items: Item[]): boolean {
18	  return items.length === BLOCK_SIZE && items.every((item) => item.type === items[0].type);
19	}
20	
21	function sumIndividualBasePremiums(items: Item[]): number {
22	  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
23	}
24	
25	function calculateBasePremium(items: Item[]): number {
26	  return isBlockOfThreeSameType(items) ? BLOCK_OF_THREE_PREMIUM : sumIndividualBasePremiums(items);
27	}
28	
29	export function quote({ items }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
30	  const basePremium = calculateBasePremium(items);
31	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
32	  return { premium: basePremium + firstInsuranceSurcharges + PROCESSING_FEE };
33	}
